+    #[test]
+    fn all_presets_have_main_slot() {
+        assert!(grid_4().arrangement.has_main_slot());
+        assert!(main_side().arrangement.has_main_slot());
+        assert!(stacked().arrangement.has_main_slot());
+        assert!(main_bottom().arrangement.has_main_slot());
